from haystack.components.retrievers import InMemoryEmbeddingRetriever
import statistics

class RelevanceMonitor:
    def __init__(self, score_threshold: float = 0.3):
        self.score_threshold = score_threshold

    def run(self, documents: list) -> dict:
        if not documents:
            raise ValueError('Retriever returned empty documents')

        scores = [doc.metadata.get('score', 0) for doc in documents]
        avg_score = statistics.mean(scores)

        if avg_score < self.score_threshold:
            raise ValueError(f'Low relevance detected: avg_score={avg_score:.3f}')

        return {'documents': documents, 'avg_relevance': avg_score}

# Pipeline integration
pipe.add_component('relevance_check', RelevanceMonitor())
pipe.connect('retriever.documents', 'relevance_check.documents')
pipe.connect('relevance_check', 'generator.documents')

from sentence_transformers import SentenceTransformer
import numpy as np

class HallucinationDetector:
    def __init__(self):
        self.model = SentenceTransformer('all-MiniLM-L6-v2')
        self.similarity_threshold = 0.4

    def run(self, documents: list, generated_text: str) -> dict:
        if not documents:
            raise ValueError('No context for hallucination check')

        context_texts = [doc.content for doc in documents]
        embeddings = self.model.encode(context_texts + [generated_text])

        similarities = np.dot(embeddings[-1], embeddings[:-1])
        max_similarity = np.max(similarities)

        if max_similarity < self.similarity_threshold:
            raise ValueError(f'Hallucination detected: similarity={max_similarity:.3f}')

        return {'text': generated_text, 'grounded': True}

pipe.add_component('hallucination_check', HallucinationDetector())
pipe.connect('generator.text', 'hallucination_check.generated_text')
pipe.connect('retriever.documents', 'hallucination_check.documents')

