from haystack.components.retrievers import InMemoryBM25Retriever

class FallbackRetriever:
    def __init__(self, embedding_retriever, keyword_retriever):
        self.embedding = embedding_retriever
        self.keyword = keyword_retriever

    def run(self, query: str, **kwargs) -> dict:
        try:
            result = self.embedding.run(query=query, **kwargs)
            if len(result.get('documents', [])) < 3:
                raise ValueError('Insufficient embedding results')
            return result
        except Exception:
            print('Embedding failed, falling back to keyword')
            return self.keyword.run(query=query, **kwargs)

